"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[37086],{21912:e=>{e.exports=JSON.parse('{"functions":[{"name":"isEnvelope","desc":"Whether a table read from teleport data is one of our envelopes (versus a legacy/hand-written flat\\ntable, which carries data keys at the root).","params":[{"name":"raw","desc":"","lua_type":"any"}],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"static","source":{"line":48,"path":"src/teleportserviceutils/src/Server/TeleportDataEnvelopeUtils.lua"}},{"name":"build","desc":"Assembles an envelope from a shared slice and a map of per-player slices keyed by UserId. Empty\\nsections are omitted, so a teleport carrying nothing serializes to `{}`.","params":[{"name":"sharedSlice","desc":"applied to every arriving player","lua_type":"TeleportDataSlice?"},{"name":"perPlayerByUserId","desc":"keyed by stringified UserId","lua_type":"{ [string]: TeleportDataSlice }?"}],"returns":[{"desc":"","lua_type":"{ [string]: any }"}],"function_type":"static","source":{"line":64,"path":"src/teleportserviceutils/src/Server/TeleportDataEnvelopeUtils.lua"}},{"name":"readSlice","desc":"Reads the slice a specific player arrived with: the shared slice merged with that player\'s own\\n(per-player wins on conflict, being the more specific). A non-envelope table is returned as-is\\n(legacy/hand-written flat data). Returns nil when the player carried nothing.","params":[{"name":"raw","desc":"the raw arrived teleport data","lua_type":"any"},{"name":"userId","desc":"the arriving player\'s UserId","lua_type":"number | string"}],"returns":[{"desc":"","lua_type":"TeleportDataSlice?"}],"function_type":"static","source":{"line":90,"path":"src/teleportserviceutils/src/Server/TeleportDataEnvelopeUtils.lua"}},{"name":"measureBytes","desc":"Approximate serialized byte size of teleport data, via its JSON encoding. Encoding also fails\\nloudly on genuinely un-encodable data (a cyclic table, a function value), so that surfaces here at\\nbuild time rather than as a broken teleport.","params":[{"name":"data","desc":"","lua_type":"any"}],"returns":[{"desc":"","lua_type":"number"}],"function_type":"static","source":{"line":133,"path":"src/teleportserviceutils/src/Server/TeleportDataEnvelopeUtils.lua"}},{"name":"classifySize","desc":"Classifies teleport data against the size budget: `ok`, `warn` (approaching the cap), or `over`\\n(past it -- will likely be dropped/error by Roblox).","params":[{"name":"data","desc":"","lua_type":"any"}],"returns":[{"desc":"","lua_type":"SizeClassification"}],"function_type":"static","source":{"line":152,"path":"src/teleportserviceutils/src/Server/TeleportDataEnvelopeUtils.lua"}}],"properties":[],"types":[],"name":"TeleportDataEnvelopeUtils","desc":"Pure assembly and reading of the per-player teleport-data envelope, plus the size guard.\\n\\nA group teleport carries a single [TeleportData] table that every arriving player reads back\\nthrough `GetJoinData().TeleportData`. To carry *per-player* data we wrap the contributions in an\\nenvelope: shared keys under one reserved key, and each player\'s slice under another keyed by\\nstringified `UserId` (the only identity stable across a teleport). Each player merges the shared\\nslice with their own on arrival. A non-envelope table (an in-flight teleport from a build predating\\nthis, or a hand-written `TeleportData`) is read as-is, so the change is backward compatible.\\n\\nAll logic here is pure and keyed by plain numbers, so it is unit tested without any [Player].","realm":["Server"],"source":{"line":17,"path":"src/teleportserviceutils/src/Server/TeleportDataEnvelopeUtils.lua"}}')}}]);